def retry_generation(
    operation,
    retries=5,
    delay=2
):

    import time

    last_error = None

    for attempt in range(retries):

        try:
            return operation()

        except Exception as error:

            last_error = error

            print(
                f"[Retry] Attempt "
                f"{attempt + 1}/{retries} failed"
            )

            if attempt < retries - 1:
                time.sleep(delay)

    raise last_error

